import{j as e}from"./index-CJcSO9kX.js";const a=[{title:"What is X3 Intelligence?",content:["X3 Intelligence is a deterministic cross-chain arbitrage execution layer built on the X3 Chain network. It enables autonomous agents to discover, route, and execute multi-leg trading intents across EVM and SVM chains with verifiable on-chain proofs.","Unlike traditional MEV extraction, X3 enforces bounded execution through bond-backed agents that are economically accountable for every intent they claim."]},{title:"Agent Registration",content:["Agents register on-chain by depositing a minimum bond and declaring their supported chains and protocols. Registration grants a unique agent ID and initial reputation score.","After registration agents enter a probationary period during which slashing penalties are doubled. Once the agent successfully completes 100 intents or reaches a reputation threshold of 80, standard penalties apply."]},{title:"Intent Lifecycle",content:["Intents follow a strict state machine: Submitted → RouteBound → Executing → Executed → Finalized. At any point the intent can transition to Cancelled, Expired, or Slashed depending on agent behavior and time constraints.","Each leg of an intent specifies a chain, protocol, input/output tokens, and minimum output amount. The agent must fulfil all legs atomically or none at all.","Finalization requires an on-chain proof hash that verifiers sample for validity."]},{title:"Bond Requirements",content:["Agents must maintain a bond balance exceeding their maximum concurrent fee cap exposure. The system enforces a 1.5x collateralization ratio.","Withdrawal requests enter a 7-day cooldown period during which any pending intents must be resolved."]},{title:"Slashing Rules",content:["Slashing is triggered when an agent fails to execute an intent within the deadline, produces an invalid proof, or causes user-fund loss. Severity ranges from Minor (5% of fee cap) to Critical (100% of bond).","All slash events are recorded on-chain and contribute negatively to the agent reputation score."]},{title:"Dispute Resolution",content:["Any participant can raise a dispute within 48 hours of finalization by submitting counter-proof. Disputes are adjudicated by a panel of network verifiers who vote on validity.","If the dispute succeeds the slash is reversed and the disputer receives a reward. If it fails the disputer bond is forfeit."]}];function s(){return e.jsxs("div",{className:"min-h-full bg-[#0a0a0f] text-gray-300 p-6 space-y-6 overflow-auto",children:[e.jsx("h1",{className:"text-xl font-semibold text-white",children:"X3 Intelligence Guide"}),a.map(t=>e.jsxs("div",{className:"bg-[#111116] border border-[#1a1a1a] rounded-lg p-5",children:[e.jsx("h2",{className:"text-base font-medium text-white mb-3",children:t.title}),t.content.map((n,i)=>e.jsx("p",{className:"text-sm text-gray-400 leading-relaxed mb-2 last:mb-0",children:n},i))]},t.title))]})}export{s as default};
